  void saveNestedMapToFile(dynamic nestedMap) {
    debugPrint("save");
    // 중첩된 Map을 JSON으로 변환
    final jsonMap = nestedMap.map((outerKey, innerMap) {
      return MapEntry(
        outerKey,
        innerMap.map((innerKey, value) => MapEntry(innerKey, value.toJson())),
      );
    }); // JSON 문자열로 변환
    final jsonString = jsonEncode(jsonMap);

    saveJsonToFile(Constants.dataPath, jsonString); // 저장하거나 파일에 기록
  }

  Future<void> startSocket() async {
    while (!_isConnected) {
      Socket socket;

      try {
        if (FFAppState().socket == null) {
          FFAppState().socket = await Socket.connect('127.0.0.1', 12345);
        }
        socket = FFAppState().socket!;
        _isConnected = true;
        logger.i('Connected to server');
        try { DataFileLogger().logConnection('CONNECTED', detail: '127.0.0.1:12345'); } catch (_) {}

        // 데이터 버퍼 생성
        Uint8List? buffer;

        // 데이터 수신
        socket.listen(
            (Uint8List packet) {
              logger.i('get data from server!!');
              // 기존 버퍼에 새 데이터 추가
              if (buffer == null) {
                buffer = packet;
              } else {
                buffer = Uint8List.fromList(buffer! + packet);
              }

              // 버퍼에 충분한 데이터가 있는지 확인
              while (buffer != null && buffer!.length >= 4) {
                // JSON 길이 추출
                final lengthData = buffer!.sublist(0, 4); // JSON 길이
                final messageLength =
                    ByteData.sublistView(lengthData).getUint32(0);

                // 버퍼에 JSON 데이터까지 충분히 도착했는지 확인
                if (buffer!.length < 4 + messageLength) {
                  // 아직 데이터가 부족하면 더 기다림
                  break;
                }

                // JSON 데이터 추출
                final jsonData =
                    utf8.decode(buffer!.sublist(4, 4 + messageLength));
                final receivedMap = json.decode(jsonData);

                // 측정값
                if (receivedMap.containsKey('date')) {
                  String date = receivedMap["date"];
                  String name = receivedMap["name"];

                  // 수신 데이터 로깅
                  try { DataFileLogger().logReceived(name, date, receivedMap["values"] ?? []); } catch (_) {}

                  if (!Constants.names.contains(name)) {
                    return;
                  }

                  if (!Measurements.dateList.contains(date)) {
                    Measurements.dateList.add(date);
                    Measurements.dateList.sort((a, b) {
                      // 문자열을 DateTime으로 변환 후 비교
                      DateTime dateA = DateTime.parse(a);
                      DateTime dateB = DateTime.parse(b);
                      return dateA.compareTo(dateB);
                    });
                  }

                  Measurements? data;
                  try {
                    if (Measurements.data[name]!.containsKey(date)) {
                      final existing = Measurements.data[name]![date]!;
                      final ok = existing.writeValue(receivedMap["values"]);
                      if (!ok) {
                        logger.e('writeValue 실패 → 저장 스킵. name=$name, date=$date');
                        // 남은 버퍼 진행을 위해 아래 cleanup으로 fall-through
                      }
                      data = existing;
                    } else {
                      data = Measurements.fromServer(receivedMap);
                    }
                  } catch (e) {
                    // fromServer/writeValue 에서 길이 불일치 등 → 데이터 오염 방지를 위해 저장 안 함
                    logger.e('측정 데이터 생성 실패: $e');
                    data = null;
                  }

                  // SQLite에 저장 (실패해도 UI는 계속 동작)
                  if (data != null) {
                    DatabaseHelper()
                        .saveMeasurements(data)
                        .catchError((e, st) {
                      logger.e('saveMeasurements 실패: $e\n$st');
                    });
                  }

                  // UI 업데이트 (dispose 이후 호출 방지)
                  if (mounted) setState(() {
                    String name = receivedMap['name'];
                    int index = Constants.names.indexOf(name);
                    if (index == -1) {
                      debugPrint("알 수 없는 name: $name");
                      return; // 리스트에 없는 이름이면 무시
                    }

                    receivedImages[index] = [];

                    if (receivedMap['image'] != null &&
                        receivedMap['image'] is List &&
                        receivedMap['image'].length >= 2) {
                      receivedImages[index] = [
                        base64Decode(receivedMap['image'][0]),
                        base64Decode(receivedMap['image'][1]),
                      ];
                    } else {
                      receivedImages[index] = [null, null]; // 또는 빈 리스트로 초기화
                      debugPrint("받은 이미지가 없습니다. 빈 리스트로 처리합니다.");
                    }
                    // receivedImages[
                    //     Constants.names.indexOf(receivedMap['name'])] = [];
                    // receivedImages[Constants.names.indexOf(receivedMap['name'])]
                    //     .add(base64Decode(receivedMap['image'][0]));
                    // receivedImages[Constants.names.indexOf(receivedMap['name'])]
                    //     .add(base64Decode(receivedMap['image'][1]));

                    ////////////////////////////////안씀////////////////////////////////////
                    // if (!receivedImages[name].containsKey(date)){
                    //   receivedImages[name][date] = [];
                    // }
                    // receivedImages[name][date].add(base64Decode(receivedMap['image']));
                    ///////////////////////////////////////////////////////////////////////
                  });
                  // 🔹 탭 자동 전환 (setState() 끝난 바로 아래)
                    if (mounted) {
                      String receivedName = receivedMap['name'];
                      int tabToGo = Constants.names.indexOf(receivedName);

                      final controller = _model.tabBarController;

                      if (controller != null) {
                          if (controller.index != tabToGo && tabToGo >= 0) {
                              controller.animateTo(tabToGo);
                              debugPrint("📍 탭 전환됨: $receivedName → index $tabToGo");
                          }
                      }
                    }
                }

                // 차트 데이터
                else if (receivedMap.containsKey('sigma=')) {
                  FFAppState().setOutputDatas(receivedMap);
                }
                // error
                else if (receivedMap.containsKey('error')) {
                  if (!mounted) break;
                  showDialog(
                    context: context,
                    builder: (alertDialogContext) {
                      return AlertDialog(
                        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(16)),
                        title: const Text(
                          '오류',
                          style: TextStyle(
                            fontWeight: FontWeight.bold,
                          ),
                        ),
                        content: const Text(
                          '엑셀 파일을 종료하고 다시 시도해 주세요.',
                          style: TextStyle(
                            fontWeight: FontWeight.w500,
                          ),
                        ),
                        actions: [
                          ElevatedButton(
                            style: ElevatedButton.styleFrom(
                              backgroundColor: const Color(0xFF1E3A5F),
                              foregroundColor: Colors.white,
                              shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(8)),
                              elevation: 0
                            ),
                            onPressed: () => Navigator.pop(alertDialogContext),
                            child: const Text(
                              'Ok',
                              style:
                                  TextStyle(color: Colors.white), // 버튼 텍스트 색상
                            ),
                          ),
                        ],
                      );
                    },
                  );
                  FFAppState().setIsLoading(false);
                } else if (receivedMap.containsKey('done')) {
                  if (!mounted) break;
                  showDialog(
                    context: context,
                    builder: (alertDialogContext) {
                      return AlertDialog(
                        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(16)),
                        title: const Text(
                          '완료',
                          style: TextStyle(
                            fontWeight: FontWeight.bold,
                          ),
                        ),
                        content: const Text(
                          '엑셀 파일 생성을 완료했습니다.',
                          style: TextStyle(
                            fontWeight: FontWeight.w500,
                          ),
                        ),
                        actions: [
                          ElevatedButton(
                            style: ElevatedButton.styleFrom(
                              backgroundColor: const Color(0xFF1E3A5F),
                              foregroundColor: Colors.white,
                              shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(8)),
                              elevation: 0
                            ),
                            onPressed: () => Navigator.pop(alertDialogContext),
                            child: const Text(
                              'Ok',
                              style:
                                  TextStyle(color: Colors.white), // 버튼 텍스트 색상
                            ),
                          ),
                        ],
                      );
                    },
                  );
                  FFAppState().setIsLoading(false);
                } else if (receivedMap.containsKey('connect')) {
                  FFAppState().setPLCConnect(true);
                }
                // 처리 완료한 데이터 제거
                if (buffer!.length > 4 + messageLength) {
                  buffer = buffer!.sublist(4 + messageLength); // 남은 데이터 유지
                } else {
                  buffer = null; // 모든 데이터 처리 완료
                }
              }
            },
            onError: (error) => {
                  logger.e("Socket Error : $error"),
                  _isConnected = false,
                  FFAppState().socket = null
                },
            onDone: () {
              logger.i("Conection Closed.");
              _isConnected = false;
              FFAppState().socket = null;
              startSocket();
            });
      } catch (e) {
        logger.e('Error: $e');
        FFAppState().socket = null;
        await Future.delayed(const Duration(seconds: 5));
      }
    }
  }

  // Future<void> saveExcelFile(String startDate){

